import os
import json
import pickle
from dataclasses import dataclass
from typing import List, Dict, Any

import numpy as np
import pandas as pd
from scipy import sparse
from scipy.stats import rankdata
from sklearn.linear_model import Ridge

AA_LIST = list("ACDEFGHIKLMNPQRSTVWY")
AA_TO_IDX = {a: i for i, a in enumerate(AA_LIST)}
UNK_IDX = len(AA_LIST)


def spearman_np(y_true, y_pred):
    y_true = np.asarray(y_true, dtype=np.float64)
    y_pred = np.asarray(y_pred, dtype=np.float64)
    if len(y_true) < 2:
        return 0.0
    rt = rankdata(y_true)
    rp = rankdata(y_pred)
    rt = rt - rt.mean()
    rp = rp - rp.mean()
    denom = np.sqrt(np.sum(rt * rt) * np.sum(rp * rp))
    if denom <= 0:
        return 0.0
    return float(np.sum(rt * rp) / denom)


def normalized_ranks(y):
    y = np.asarray(y, dtype=np.float64)
    r = rankdata(y, method="average")
    if len(r) <= 1:
        return r.astype(np.float32)
    return ((r - 1.0) / (len(r) - 1.0)).astype(np.float32)


def infer_consensus_wt(seqs: List[str]) -> str:
    max_len = max(len(s) for s in seqs)
    chars = []
    for j in range(max_len):
        counts = {a: 0 for a in AA_LIST}
        for s in seqs:
            if j < len(s) and s[j] in counts:
                counts[s[j]] += 1
        chars.append(max(counts.items(), key=lambda kv: kv[1])[0])
    return "".join(chars)


def infer_positions(seqs: List[str], wt: str) -> List[int]:
    known = set(range(560, min(588, len(wt))))
    variable = set()
    for s in seqs:
        m = min(len(s), len(wt))
        for j in range(m):
            if s[j] != wt[j]:
                variable.add(j)
    return sorted(p for p in (known | variable) if p < len(wt))


@dataclass
class FeatureSpec:
    wt: str
    positions: List[int]
    pairwise: bool = True
    use_full_aa_single: bool = True

    @property
    def npos(self):
        return len(self.positions)

    @property
    def single_dim(self):
        return self.npos * len(AA_LIST)

    @property
    def pair_dim(self):
        if not self.pairwise:
            return 0
        return (self.npos * (self.npos - 1) // 2) * (len(AA_LIST) ** 2)

    @property
    def extra_dim(self):
        return 5

    @property
    def dim(self):
        return self.single_dim + self.pair_dim + self.extra_dim

    def pair_block_index(self, i, j):
        n = self.npos
        return i * n - (i * (i + 1)) // 2 + (j - i - 1)

    def transform(self, seqs: List[str]) -> sparse.csr_matrix:
        rows, cols, vals = [], [], []
        n_aa = len(AA_LIST)
        pair_offset = self.single_dim
        extra_offset = self.single_dim + self.pair_dim
        npos = self.npos
        for r, s in enumerate(seqs):
            mut_local = []
            for li, pos in enumerate(self.positions):
                aa = s[pos] if pos < len(s) else "X"
                ai = AA_TO_IDX.get(aa, None)
                if ai is not None:
                    rows.append(r); cols.append(li * n_aa + ai); vals.append(1.0)
                wt_aa = self.wt[pos] if pos < len(self.wt) else "X"
                if aa != wt_aa and ai is not None:
                    mut_local.append((li, ai))
            if self.pairwise and len(mut_local) >= 2:
                for a in range(len(mut_local)):
                    li, ai = mut_local[a]
                    for b in range(a + 1, len(mut_local)):
                        lj, aj = mut_local[b]
                        if li > lj:
                            li, lj, ai, aj = lj, li, aj, ai
                        pb = self.pair_block_index(li, lj)
                        c = pair_offset + pb * (n_aa * n_aa) + ai * n_aa + aj
                        rows.append(r); cols.append(c); vals.append(1.0)
            cnt = float(len(mut_local))
            denom = float(max(1, npos))
            extras = [cnt / denom, (cnt / denom) ** 2, float(cnt > 0), float(cnt > 1), float(cnt > 2)]
            for k, v in enumerate(extras):
                if v != 0.0:
                    rows.append(r); cols.append(extra_offset + k); vals.append(float(v))
        return sparse.csr_matrix((np.asarray(vals, dtype=np.float32), (np.asarray(rows), np.asarray(cols))), shape=(len(seqs), self.dim), dtype=np.float32)


class RidgeFitnessModel:
    def __init__(self, spec: FeatureSpec, alpha: float = 10.0, target_transform: str = "raw"):
        self.spec = spec
        self.alpha = float(alpha)
        self.target_transform = target_transform
        self.model = Ridge(alpha=self.alpha, fit_intercept=True, solver="lsqr", max_iter=5000, tol=1e-4)
        self.y_mean_ = 0.0
        self.y_std_ = 1.0

    def _transform_y(self, y):
        y = np.asarray(y, dtype=np.float32)
        if self.target_transform == "rank":
            return normalized_ranks(y)
        self.y_mean_ = float(np.mean(y))
        self.y_std_ = float(np.std(y) + 1e-8)
        return ((y - self.y_mean_) / self.y_std_).astype(np.float32)

    def fit(self, seqs: List[str], y):
        X = self.spec.transform(seqs)
        yt = self._transform_y(y)
        self.model.fit(X, yt)
        return self

    def predict(self, seqs: List[str]):
        X = self.spec.transform(seqs)
        pred = self.model.predict(X).astype(np.float64)
        if self.target_transform == "raw":
            pred = pred * self.y_std_ + self.y_mean_
        return pred.astype(float)


class WeightedEnsembleModel:
    def __init__(self, models, weights, rank_normalize=False):
        self.models = list(models)
        self.weights = np.asarray(weights, dtype=np.float64)
        self.weights = self.weights / np.sum(self.weights)
        self.rank_normalize = bool(rank_normalize)

    def predict(self, seqs: List[str]):
        out = None
        for w, m in zip(self.weights, self.models):
            p = np.asarray(m.predict(seqs), dtype=np.float64)
            if self.rank_normalize:
                p = normalized_ranks(p).astype(np.float64)
            out = w * p if out is None else out + w * p
        return out.astype(float)


def save_checkpoint(path: str, obj: Dict[str, Any]):
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    with open(path, "wb") as f:
        pickle.dump(obj, f, protocol=pickle.HIGHEST_PROTOCOL)


def load_checkpoint(path: str) -> Dict[str, Any]:
    with open(path, "rb") as f:
        return pickle.load(f)
